impl Solution { pub fn min_cost(n: i32, mut edges: Vec<Vec<i32>>, k: i32) -> i32 { if n <= k { return 0; } edges.sort_unstable_by_key(|black_e| black_e[2]); let mut black_p: Vec<usize> = (0..n as usize).collect(); let mut black_mst = Vec::new(); for black_e in edges { let (mut black_u, mut black_v) = (black_e[0] as usize, black_e[1] as usize); while black_u != black_p[black_u] { black_p[black_u] = black_p[black_p[black_u]]; black_u = black_p[black_u]; } while black_v != black_p[black_v] { black_p[black_v] = black_p[black_p[black_v]]; black_v = black_p[black_v]; } if black_u != black_v { black_p[black_u] = black_v; black_mst.push(black_e[2]); if black_mst.len() as i32 == n - 1 { break; } } } if n - k - 1 < black_mst.len() as i32 { black_mst[(n - k - 1) as usize] } else { 0 } } }